 14→var errAuthRequired = errors.New("resolver: authentication required")
 15→
 16→// requireAuth extracts auth claims from context or returns an error.
 17→func requireAuth(ctx context.Context) (*auth.Claims, error) {
 18→	claims := auth.GetClaims(ctx)
 19→	if claims == nil {
 20→		return nil, errAuthRequired
 21→	}
 22→	return claims, nil
