 93→// sensitivityToString converts a GraphQL SensitivityLevel to lowercase DB string.
 94→// Returns "normal" if nil.
 95→func sensitivityToString(s *model.SensitivityLevel) string {
 96→	if s == nil {
 97→		return "normal"
 98→	}
 99→	return strings.ToLower(string(*s))
100→}
