  1→interface CaptureResult {
  2→  success: boolean;
  3→  error?: string;
  4→}
  5→
  6→document.addEventListener("DOMContentLoaded", async () => {
  7→  const form = document.getElementById("capture-form") as HTMLFormElement;
  8→  const urlInput = document.getElementById("url") as HTMLInputElement;
  9→  const titleInput = document.getElementById("title") as HTMLInputElement;
 10→  const selectionInput = document.getElementById(
 11→    "selection",
 12→  ) as HTMLTextAreaElement;
 13→  const tagsInput = document.getElementById("tags") as HTMLInputElement;
 14→  const sensitivitySelect = document.getElementById(
 15→    "sensitivity",
 16→  ) as HTMLSelectElement;
 17→  const saveBtn = document.getElementById("save-btn") as HTMLButtonElement;
 18→  const statusDiv = document.getElementById("status") as HTMLDivElement;
 19→  const notConfigured = document.getElementById(
 20→    "not-configured",
 21→  ) as HTMLDivElement;
 22→  const openOptions = document.getElementById(
 23→    "open-options",
 24→  ) as HTMLAnchorElement;
 25→
 26→  // Check if configured
 27→  const { apiUrl, jwtToken } = await chrome.storage.local.get([
 28→    "apiUrl",
 29→    "jwtToken",
 30→  ]);
 31→
 32→  if (!apiUrl || !jwtToken) {
 33→    notConfigured.hidden = false;
 34→    form.hidden = true;
 35→    openOptions.addEventListener("click", (e: Event) => {
 36→      e.preventDefault();
 37→      chrome.runtime.openOptionsPage();
 38→    });
 39→    return;
 40→  }
 41→
 42→  // Get current tab info
 43→  const [tab] = await chrome.tabs.query({
 44→    active: true,
 45→    currentWindow: true,
 46→  });
 47→  if (tab) {
 48→    urlInput.value = tab.url || "";
 49→    titleInput.value = tab.title || "";
 50→
 51→    // Try to get selected text from the page
 52→    try {
 53→      const results = await chrome.scripting.executeScript({
 54→        target: { tabId: tab.id! },
 55→        files: ["content/content.js"],
 56→      });
 57→      if (results && results[0] && results[0].result) {
 58→        selectionInput.value = results[0].result as string;
 59→      }
 60→    } catch {
 61→      // Content script injection may fail on chrome:// or extension pages
 62→    }
 63→  }
 64→
 65→  form.addEventListener("submit", async (e: Event) => {
 66→    e.preventDefault();
 67→    saveBtn.disabled = true;
 68→    saveBtn.textContent = "Saving...";
 69→    statusDiv.hidden = true;
 70→
 71→    const rawTags = tagsInput.value
 72→      .split(",")
 73→      .map((t) => t.trim())
 74→      .filter(Boolean);
 75→
 76→    const input = {
 77→      url: urlInput.value,
 78→      title: titleInput.value || null,
 79→      selection: selectionInput.value || null,
 80→      tags: rawTags.length > 0 ? rawTags : null,
 81→      sensitivity: sensitivitySelect.value,
 82→    };
 83→
 84→    try {
 85→      const response: CaptureResult = await chrome.runtime.sendMessage({
 86→        action: "captureBookmark",
 87→        input,
 88→      });
 89→
 90→      if (response.success) {
 91→        showStatus("Bookmark saved!", "success");
 92→        saveBtn.textContent = "Saved";
 93→      } else {
 94→        showStatus(response.error || "Failed to save bookmark", "error");
 95→        saveBtn.disabled = false;
 96→        saveBtn.textContent = "Save Bookmark";
 97→      }
 98→    } catch (err) {
 99→      showStatus("Extension error: " + (err as Error).message, "error");
100→      saveBtn.disabled = false;
101→      saveBtn.textContent = "Save Bookmark";
102→    }
103→  });
104→
105→  function showStatus(message: string, type: string): void {
106→    statusDiv.textContent = message;
107→    statusDiv.className = type;
108→    statusDiv.hidden = false;
109→  }
110→});
