 1→package com.flotsam.capture.data
 2→
 3→import android.content.Context
 4→import androidx.datastore.core.DataStore
 5→import androidx.datastore.preferences.core.Preferences
 6→import androidx.datastore.preferences.core.edit
 7→import androidx.datastore.preferences.core.stringPreferencesKey
 8→import androidx.datastore.preferences.preferencesDataStore
 9→import kotlinx.coroutines.flow.Flow
10→import kotlinx.coroutines.flow.map
11→
12→private val Context.dataStore: DataStore<Preferences> by preferencesDataStore(name = "settings")
13→
14→class SettingsStore(private val context: Context) {
15→
16→    private companion object {
17→        val API_URL = stringPreferencesKey("api_url")
18→        val JWT_TOKEN = stringPreferencesKey("jwt_token")
19→    }
20→
21→    val apiUrl: Flow<String> = context.dataStore.data.map { prefs ->
22→        prefs[API_URL] ?: ""
23→    }
24→
25→    val jwtToken: Flow<String> = context.dataStore.data.map { prefs ->
26→        prefs[JWT_TOKEN] ?: ""
27→    }
28→
29→    suspend fun setApiUrl(url: String) {
30→        context.dataStore.edit { prefs -> prefs[API_URL] = url }
31→    }
32→
33→    suspend fun setJwtToken(token: String) {
34→        context.dataStore.edit { prefs -> prefs[JWT_TOKEN] = token }
35→    }
36→}
