158→// GraphQL query and mutation strings.
159→const (
160→	loginMutation = `mutation Login($input: LoginInput!) {
161→  login(input: $input) {
162→    token
163→    user { id email displayName }
164→  }
165→}`
166→
167→	captureNoteMutation = `mutation CaptureNote($input: NoteInput!) {
168→  captureNote(input: $input) {
169→    id type status sensitivity title tags source createdAt
170→  }
171→}`
172→
173→	captureBookmarkMutation = `mutation CaptureBookmark($input: BookmarkInput!) {
174→  captureBookmark(input: $input) {
175→    id type status sensitivity title contentUrl tags source createdAt
176→  }
177→}`
178→
179→	searchQuery = `query Search($query: String!, $filter: ItemFilter, $limit: Int) {
180→  search(query: $query, filter: $filter, limit: $limit) {
181→    items { id type status sensitivity title contentText contentUrl tags createdAt }
182→    total
183→    hasMore
184→  }
185→}`
186→
187→	listQuery = `query Items($filter: ItemFilter, $limit: Int, $offset: Int, $sort: ItemSort) {
188→  items(filter: $filter, limit: $limit, offset: $offset, sort: $sort) {
189→    items { id type status sensitivity title contentText contentUrl tags createdAt }
190→    total
191→    hasMore
192→  }
193→}`
194→)
195→
196→// Login authenticates with the API and returns a token and user info.
197→func (c *Client) Login(ctx context.Context, email, password string) (string, UserInfo, error) {
198→	var resp struct {
199→		Login struct {
200→			Token string   `json:"token"`
201→			User  UserInfo `json:"user"`
202→		} `json:"login"`
203→	}
204→
205→	vars := map[string]any{
206→		"input": map[string]any{
207→			"email":    email,
208→			"password": password,
209→		},
210→	}
211→
212→	if err := c.Do(ctx, loginMutation, vars, &resp); err != nil {
213→		return "", UserInfo{}, err
214→	}
215→
216→	return resp.Login.Token, resp.Login.User, nil
217→}
