import { Client, cacheExchange, fetchExchange } from 'urql'
import { authExchange } from '@urql/exchange-auth'
import { useAuthStore } from '@/stores/authStore'

export const urqlClient = new Client({
  url: '/graphql',
  exchanges: [
    cacheExchange,
    authExchange(async (utils) => ({
      addAuthToOperation(operation) {
        const token = useAuthStore.getState().getToken()
        if (!token) return operation
        return utils.appendHeaders(operation, {
          Authorization: `Bearer ${token}`,
        })
      },
      didAuthError(error) {
        return (
          error.graphQLErrors.some(
            (e) =>
              e.extensions?.code === 'FORBIDDEN' || e.extensions?.code === 'UNAUTHENTICATED',
          ) || error.response?.status === 401
        )
      },
      async refreshAuth() {
        useAuthStore.getState().logout()
      },
    })),
    fetchExchange,
  ],
})

import { create } from 'zustand'

const TOKEN_KEY = 'flotsam_token'

interface User {
  id: string
  email: string
  displayName: string | null
}

interface AuthState {
  token: string | null
  user: User | null
  loading: boolean

  initialize: () => void
  setAuth: (token: string, user: User) => void
  logout: () => void
  getToken: () => string | null
}

export const useAuthStore = create<AuthState>()((set, get) => ({
  token: null,
  user: null,
  loading: true,

  initialize: () => {
    const token = localStorage.getItem(TOKEN_KEY)
    if (token) {
      set({ token, loading: false })
    } else {
      set({ loading: false })
    }
  },

  setAuth: (token: string, user: User) => {
    localStorage.setItem(TOKEN_KEY, token)
    set({ token, user, loading: false })
  },

  logout: () => {
    localStorage.removeItem(TOKEN_KEY)
    set({ token: null, user: null })
  },

  getToken: () => {
    return get().token
  },
}))

package middleware

import (
	"log/slog"
	"net/http"
	"strings"

	"github.com/ketang/flotsam/api/internal/auth"
)

// Auth validates the Bearer JWT token from the Authorization header.
// On success, claims are stored in the request context via auth.WithClaims.
// On failure, responds with 401 Unauthorized.
func Auth(validator auth.Validator) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			token, ok := bearerToken(r)
			if !ok {
				slog.WarnContext(r.Context(), "auth: missing or malformed authorization header",
					"request_id", requestIDFromContext(r.Context()),
					"method", r.Method,
					"path", r.URL.Path,
					"remote_addr", r.RemoteAddr,
				)
				w.Header().Set("WWW-Authenticate", `Bearer realm="flotsam"`)
				http.Error(w, "missing or malformed authorization header", http.StatusUnauthorized)
				return
			}

			claims, err := validator.Validate(token)
			if err != nil {
				slog.WarnContext(r.Context(), "auth: invalid or expired token",
					"request_id", requestIDFromContext(r.Context()),
					"method", r.Method,
					"path", r.URL.Path,
					"remote_addr", r.RemoteAddr,
					"error", err,
				)
				w.Header().Set("WWW-Authenticate", `Bearer realm="flotsam", error="invalid_token"`)
				http.Error(w, "invalid or expired token", http.StatusUnauthorized)
				return
			}

			ctx := auth.WithClaims(r.Context(), claims)
			next.ServeHTTP(w, r.WithContext(ctx))
		})
	}
}

// OptionalAuth validates a Bearer token if present but allows unauthenticated requests.
// If a token is present and valid, claims are stored in context.
// If a token is present but invalid, responds with 401.
// If no token is present, the request proceeds without claims.
func OptionalAuth(validator auth.Validator) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			token, ok := bearerToken(r)
			if !ok {
				next.ServeHTTP(w, r)
				return
			}

			claims, err := validator.Validate(token)
			if err != nil {
				slog.WarnContext(r.Context(), "auth: invalid or expired token",
					"request_id", requestIDFromContext(r.Context()),
					"method", r.Method,
					"path", r.URL.Path,
					"remote_addr", r.RemoteAddr,
					"error", err,
				)
				w.Header().Set("WWW-Authenticate", `Bearer realm="flotsam", error="invalid_token"`)
				http.Error(w, "invalid or expired token", http.StatusUnauthorized)
				return
			}

			ctx := auth.WithClaims(r.Context(), claims)
			next.ServeHTTP(w, r.WithContext(ctx))
		})
	}
}

// bearerToken extracts the token from "Authorization: Bearer <token>".
func bearerToken(r *http.Request) (string, bool) {
	header := r.Header.Get("Authorization")
	if header == "" {
		return "", false
	}
	parts := strings.SplitN(header, " ", 2)
	if len(parts) != 2 || !strings.EqualFold(parts[0], "bearer") {
		return "", false
	}
	token := strings.TrimSpace(parts[1])
	if token == "" {
		return "", false
	}
	return token, true
}

