interface BookmarkInput {
  url: string;
  title: string | null;
  selection: string | null;
  tags: string[] | null;
  sensitivity: string;
}

interface CaptureMessage {
  action: "captureBookmark";
  input: BookmarkInput;
}

interface CaptureResult {
  success: boolean;
  error?: string;
  data?: {
    id: string;
    status: string;
    title: string;
    tags: string[];
  };
}

interface GraphQLResponse {
  data?: {
    captureBookmark: {
      id: string;
      status: string;
      title: string;
      tags: string[];
    };
  };
  errors?: Array<{ message: string }>;
}

const CAPTURE_MUTATION = `
  mutation CaptureBookmark($input: BookmarkInput!) {
    captureBookmark(input: $input) {
      id
      status
      title
      tags
    }
  }
`;

chrome.runtime.onMessage.addListener(
  (
    message: CaptureMessage,
    _sender: chrome.runtime.MessageSender,
    sendResponse: (response: CaptureResult) => void,
  ) => {
    if (message.action === "captureBookmark") {
      handleCapture(message.input).then(sendResponse);
      return true; // keep message channel open for async response
    }
  },
);

async function handleCapture(input: BookmarkInput): Promise<CaptureResult> {
  try {
    const { apiUrl, jwtToken } = await chrome.storage.local.get([
      "apiUrl",
      "jwtToken",
    ]);

    if (!apiUrl || !jwtToken) {
      return { success: false, error: "Extension not configured" };
    }

    const graphqlUrl = (apiUrl as string).replace(/\/+$/, "") + "/graphql";

    const res = await fetch(graphqlUrl, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: "Bearer " + jwtToken,
      },
      body: JSON.stringify({
        query: CAPTURE_MUTATION,
        variables: { input },
      }),
    });

    if (!res.ok) {
      const text = await res.text();
      return { success: false, error: `HTTP ${res.status}: ${text}` };
    }

    const json: GraphQLResponse = await res.json();

    if (json.errors && json.errors.length > 0) {
      return { success: false, error: json.errors[0].message };
    }

    return { success: true, data: json.data!.captureBookmark };
  } catch (err) {
    return { success: false, error: (err as Error).message };
  }
}

package com.flotsam.capture.network

import com.google.gson.Gson
import okhttp3.MediaType.Companion.toMediaType
import okhttp3.OkHttpClient
import okhttp3.Request
import okhttp3.RequestBody.Companion.toRequestBody
import java.io.IOException
import java.util.concurrent.TimeUnit

class GraphQLClient {

    private val client = OkHttpClient.Builder()
        .connectTimeout(30, TimeUnit.SECONDS)
        .readTimeout(30, TimeUnit.SECONDS)
        .build()

    private val gson = Gson()

    fun captureVoiceNote(
        audioKey: String,
        tags: List<String>,
        baseUrl: String,
        token: String,
    ): String {
        val tagsJson = tags.joinToString(", ") { "\"$it\"" }

        val query = """
            mutation CaptureVoiceNote(${'$'}input: VoiceNoteInput!) {
                captureVoiceNote(input: ${'$'}input) {
                    id
                    title
                    status
                }
            }
        """.trimIndent()

        val variables = mapOf(
            "input" to buildMap {
                put("audioKey", audioKey)
                put("source", "android_app")
                if (tags.isNotEmpty()) put("tags", tags)
            },
        )

        val payload = mapOf(
            "query" to query,
            "variables" to variables,
        )

        val body = gson.toJson(payload)
            .toRequestBody("application/json".toMediaType())

        val request = Request.Builder()
            .url("${baseUrl.trimEnd('/')}/graphql")
            .header("Authorization", "Bearer $token")
            .post(body)
            .build()

        val response = client.newCall(request).execute()
        if (!response.isSuccessful) {
            val errorBody = response.body?.string() ?: "Unknown error"
            throw IOException("GraphQL request failed (${response.code}): $errorBody")
        }

        return response.body?.string() ?: throw IOException("Empty response body")
    }
}

package com.flotsam.capture.network

import com.google.gson.Gson
import com.google.gson.annotations.SerializedName
import okhttp3.MediaType.Companion.toMediaType
import okhttp3.MultipartBody
import okhttp3.OkHttpClient
import okhttp3.Request
import okhttp3.RequestBody.Companion.asRequestBody
import java.io.File
import java.io.IOException
import java.util.concurrent.TimeUnit

data class UploadResponse(
    val key: String,
    @SerializedName("content_type") val contentType: String,
    val size: Long,
)

class ApiClient {

    private val client = OkHttpClient.Builder()
        .connectTimeout(30, TimeUnit.SECONDS)
        .writeTimeout(120, TimeUnit.SECONDS)
        .readTimeout(30, TimeUnit.SECONDS)
        .build()

    private val gson = Gson()

    fun uploadAudio(file: File, baseUrl: String, token: String): UploadResponse {
        val body = MultipartBody.Builder()
            .setType(MultipartBody.FORM)
            .addFormDataPart(
                "file",
                file.name,
                file.asRequestBody("audio/mp4".toMediaType()),
            )
            .build()

        val request = Request.Builder()
            .url("${baseUrl.trimEnd('/')}/upload")
            .header("Authorization", "Bearer $token")
            .post(body)
            .build()

        val response = client.newCall(request).execute()
        if (!response.isSuccessful) {
            val errorBody = response.body?.string() ?: "Unknown error"
            throw IOException("Upload failed (${response.code}): $errorBody")
        }

        val responseBody = response.body?.string()
            ?: throw IOException("Empty response body")

        return gson.fromJson(responseBody, UploadResponse::class.java)
    }

    fun testConnection(baseUrl: String): Boolean {
        val request = Request.Builder()
            .url("${baseUrl.trimEnd('/')}/health")
            .get()
            .build()

        return try {
            val response = client.newCall(request).execute()
            response.isSuccessful
        } catch (_: IOException) {
            false
        }
    }
}

