package cli

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"strings"
)

// Client is a GraphQL HTTP client for the Flotsam API.
type Client struct {
	httpClient *http.Client
	apiURL     string
	token      string
}

// NewClient creates a new GraphQL client.
func NewClient(apiURL, token string) *Client {
	return &Client{
		httpClient: &http.Client{},
		apiURL:     strings.TrimRight(apiURL, "/"),
		token:      token,
	}
}

// Item represents an item returned from the API.
type Item struct {
	ID          string   `json:"id"`
	Type        string   `json:"type"`
	Status      string   `json:"status"`
	Sensitivity string   `json:"sensitivity"`
	Title       *string  `json:"title"`
	ContentText *string  `json:"contentText"`
	ContentURL  *string  `json:"contentUrl"`
	Tags        []string `json:"tags"`
	Source      string   `json:"source"`
	CreatedAt   string   `json:"createdAt"`
	UpdatedAt   string   `json:"updatedAt"`
}

// SearchResult represents a paginated list of items.
type SearchResult struct {
	Items   []Item `json:"items"`
	Total   int    `json:"total"`
	HasMore bool   `json:"hasMore"`
}

// UserInfo represents basic user information.
type UserInfo struct {
	ID          string  `json:"id"`
	Email       string  `json:"email"`
	DisplayName *string `json:"displayName"`
}

// NoteInput holds parameters for creating a text note.
type NoteInput struct {
	Content     string   `json:"content"`
	Title       *string  `json:"title,omitempty"`
	Tags        []string `json:"tags,omitempty"`
	Sensitivity *string  `json:"sensitivity,omitempty"`
}

// BookmarkInput holds parameters for creating a bookmark.
type BookmarkInput struct {
	URL         string   `json:"url"`
	Title       *string  `json:"title,omitempty"`
	Tags        []string `json:"tags,omitempty"`
	Sensitivity *string  `json:"sensitivity,omitempty"`
}

// ListOpts holds parameters for listing items.
type ListOpts struct {
	Types  []string
	Limit  int
	Offset int
	Sort   string
}

// graphqlRequest is the JSON body sent to the GraphQL endpoint.
type graphqlRequest struct {
	Query     string         `json:"query"`
	Variables map[string]any `json:"variables,omitempty"`
}

// graphqlResponse is the JSON response from the GraphQL endpoint.
type graphqlResponse struct {
	Data   json.RawMessage `json:"data"`
	Errors []graphqlError  `json:"errors"`
}

// graphqlError represents a GraphQL error.
type graphqlError struct {
	Message string `json:"message"`
}

// Do sends a GraphQL request and decodes the response data into result.
func (c *Client) Do(ctx context.Context, query string, variables map[string]any, result any) error {
	body, err := json.Marshal(graphqlRequest{
		Query:     query,
		Variables: variables,
	})
	if err != nil {
		return fmt.Errorf("cli: marshal request: %w", err)
	}

	req, err := http.NewRequestWithContext(ctx, http.MethodPost, c.apiURL+"/graphql", bytes.NewReader(body))
	if err != nil {
		return fmt.Errorf("cli: create request: %w", err)
	}
	req.Header.Set("Content-Type", "application/json")
	if c.token != "" {
		req.Header.Set("Authorization", "Bearer "+c.token)
	}

	resp, err := c.httpClient.Do(req)
	if err != nil {
		return fmt.Errorf("cli: send request: %w", err)
	}
	defer func() { _ = resp.Body.Close() }()

	respBody, err := io.ReadAll(resp.Body)
	if err != nil {
		return fmt.Errorf("cli: read response: %w", err)
	}

	if resp.StatusCode == http.StatusUnauthorized {
		return fmt.Errorf("cli: not authenticated (run 'flotsam login' first)")
	}
	if resp.StatusCode != http.StatusOK {
		return fmt.Errorf("cli: unexpected status %d: %s", resp.StatusCode, string(respBody))
	}

	var gqlResp graphqlResponse
	if err := json.Unmarshal(respBody, &gqlResp); err != nil {
		return fmt.Errorf("cli: parse response: %w", err)
	}

	if len(gqlResp.Errors) > 0 {
		messages := make([]string, len(gqlResp.Errors))
		for i, e := range gqlResp.Errors {
			messages[i] = e.Message
		}
		return fmt.Errorf("cli: %s", strings.Join(messages, "; "))
	}

	if result != nil {
		if err := json.Unmarshal(gqlResp.Data, result); err != nil {
			return fmt.Errorf("cli: decode data: %w", err)
		}
	}

	return nil
}

// GraphQL query and mutation strings.
const (
	loginMutation = `mutation Login($input: LoginInput!) {
  login(input: $input) {
    token
    user { id email displayName }
  }
}`

	captureNoteMutation = `mutation CaptureNote($input: NoteInput!) {
  captureNote(input: $input) {
    id type status sensitivity title tags source createdAt
  }
}`

	captureBookmarkMutation = `mutation CaptureBookmark($input: BookmarkInput!) {
  captureBookmark(input: $input) {
    id type status sensitivity title contentUrl tags source createdAt
  }
}`

	searchQuery = `query Search($query: String!, $filter: ItemFilter, $limit: Int) {
  search(query: $query, filter: $filter, limit: $limit) {
    items { id type status sensitivity title contentText contentUrl tags createdAt }
    total
    hasMore
  }
}`

	listQuery = `query Items($filter: ItemFilter, $limit: Int, $offset: Int, $sort: ItemSort) {
  items(filter: $filter, limit: $limit, offset: $offset, sort: $sort) {
    items { id type status sensitivity title contentText contentUrl tags createdAt }
    total
    hasMore
  }
}`
)

// Login authenticates with the API and returns a token and user info.
func (c *Client) Login(ctx context.Context, email, password string) (string, UserInfo, error) {
	var resp struct {
		Login struct {
			Token string   `json:"token"`
			User  UserInfo `json:"user"`
		} `json:"login"`
	}

	vars := map[string]any{
		"input": map[string]any{
			"email":    email,
			"password": password,
		},
	}

	if err := c.Do(ctx, loginMutation, vars, &resp); err != nil {
		return "", UserInfo{}, err
	}

	return resp.Login.Token, resp.Login.User, nil
}

// CaptureNote creates a text note item.
func (c *Client) CaptureNote(ctx context.Context, input NoteInput) (*Item, error) {
	var resp struct {
		CaptureNote Item `json:"captureNote"`
	}

	vars := map[string]any{
		"input": map[string]any{
			"content":     input.Content,
			"title":       input.Title,
			"tags":        input.Tags,
			"sensitivity": input.Sensitivity,
		},
	}

	if err := c.Do(ctx, captureNoteMutation, vars, &resp); err != nil {
		return nil, err
	}
	return &resp.CaptureNote, nil
}

// CaptureBookmark creates a bookmark item.
func (c *Client) CaptureBookmark(ctx context.Context, input BookmarkInput) (*Item, error) {
	var resp struct {
		CaptureBookmark Item `json:"captureBookmark"`
	}

	vars := map[string]any{
		"input": map[string]any{
			"url":         input.URL,
			"title":       input.Title,
			"tags":        input.Tags,
			"sensitivity": input.Sensitivity,
		},
	}

	if err := c.Do(ctx, captureBookmarkMutation, vars, &resp); err != nil {
		return nil, err
	}
	return &resp.CaptureBookmark, nil
}

// Search performs a full-text search.
func (c *Client) Search(ctx context.Context, query string, types []string, limit int) (*SearchResult, error) {
	var resp struct {
		Search SearchResult `json:"search"`
	}

	vars := map[string]any{
		"query": query,
		"limit": limit,
	}
	if len(types) > 0 {
		vars["filter"] = map[string]any{"types": toUpperStrings(types)}
	}

	if err := c.Do(ctx, searchQuery, vars, &resp); err != nil {
		return nil, err
	}
	return &resp.Search, nil
}

// ListItems lists items with optional filters.
func (c *Client) ListItems(ctx context.Context, opts ListOpts) (*SearchResult, error) {
	var resp struct {
		Items SearchResult `json:"items"`
	}

	vars := map[string]any{
		"limit":  opts.Limit,
		"offset": opts.Offset,
	}
	if len(opts.Types) > 0 {
		vars["filter"] = map[string]any{"types": toUpperStrings(opts.Types)}
	}
	if opts.Sort != "" {
		vars["sort"] = map[string]any{
			"field":     strings.ToUpper(opts.Sort),
			"direction": "DESC",
		}
	}

	if err := c.Do(ctx, listQuery, vars, &resp); err != nil {
		return nil, err
	}
	return &resp.Items, nil
}

// toUpperStrings converts a slice of strings to uppercase.
func toUpperStrings(ss []string) []string {
	out := make([]string, len(ss))
	for i, s := range ss {
		out[i] = strings.ToUpper(s)
	}
	return out
}

