interface CaptureResult {
  success: boolean;
  error?: string;
}

document.addEventListener("DOMContentLoaded", async () => {
  const form = document.getElementById("capture-form") as HTMLFormElement;
  const urlInput = document.getElementById("url") as HTMLInputElement;
  const titleInput = document.getElementById("title") as HTMLInputElement;
  const selectionInput = document.getElementById(
    "selection",
  ) as HTMLTextAreaElement;
  const tagsInput = document.getElementById("tags") as HTMLInputElement;
  const sensitivitySelect = document.getElementById(
    "sensitivity",
  ) as HTMLSelectElement;
  const saveBtn = document.getElementById("save-btn") as HTMLButtonElement;
  const statusDiv = document.getElementById("status") as HTMLDivElement;
  const notConfigured = document.getElementById(
    "not-configured",
  ) as HTMLDivElement;
  const openOptions = document.getElementById(
    "open-options",
  ) as HTMLAnchorElement;

  // Check if configured
  const { apiUrl, jwtToken } = await chrome.storage.local.get([
    "apiUrl",
    "jwtToken",
  ]);

  if (!apiUrl || !jwtToken) {
    notConfigured.hidden = false;
    form.hidden = true;
    openOptions.addEventListener("click", (e: Event) => {
      e.preventDefault();
      chrome.runtime.openOptionsPage();
    });
    return;
  }

  // Get current tab info
  const [tab] = await chrome.tabs.query({
    active: true,
    currentWindow: true,
  });
  if (tab) {
    urlInput.value = tab.url || "";
    titleInput.value = tab.title || "";

    // Try to get selected text from the page
    try {
      const results = await chrome.scripting.executeScript({
        target: { tabId: tab.id! },
        files: ["content/content.js"],
      });
      if (results && results[0] && results[0].result) {
        selectionInput.value = results[0].result as string;
      }
    } catch {
      // Content script injection may fail on chrome:// or extension pages
    }
  }

  form.addEventListener("submit", async (e: Event) => {
    e.preventDefault();
    saveBtn.disabled = true;
    saveBtn.textContent = "Saving...";
    statusDiv.hidden = true;

    const rawTags = tagsInput.value
      .split(",")
      .map((t) => t.trim())
      .filter(Boolean);

    const input = {
      url: urlInput.value,
      title: titleInput.value || null,
      selection: selectionInput.value || null,
      tags: rawTags.length > 0 ? rawTags : null,
      sensitivity: sensitivitySelect.value,
    };

    try {
      const response: CaptureResult = await chrome.runtime.sendMessage({
        action: "captureBookmark",
        input,
      });

      if (response.success) {
        showStatus("Bookmark saved!", "success");
        saveBtn.textContent = "Saved";
      } else {
        showStatus(response.error || "Failed to save bookmark", "error");
        saveBtn.disabled = false;
        saveBtn.textContent = "Save Bookmark";
      }
    } catch (err) {
      showStatus("Extension error: " + (err as Error).message, "error");
      saveBtn.disabled = false;
      saveBtn.textContent = "Save Bookmark";
    }
  });

  function showStatus(message: string, type: string): void {
    statusDiv.textContent = message;
    statusDiv.className = type;
    statusDiv.hidden = false;
  }
});

