package resolver

import (
	"context"
	"testing"
	"time"

	"github.com/google/uuid"

	"github.com/ketang/flotsam/api/graph/model"
	"github.com/ketang/flotsam/api/internal/auth"
	"github.com/ketang/flotsam/api/internal/item"
)

func TestRequireAuth(t *testing.T) {
	t.Run("no claims returns error", func(t *testing.T) {
		_, err := requireAuth(context.Background())
		if err == nil {
			t.Fatal("expected error")
		}
		if err != errAuthRequired {
			t.Errorf("expected errAuthRequired, got %v", err)
		}
	})

	t.Run("with claims succeeds", func(t *testing.T) {
		claims := &auth.Claims{UserID: uuid.New(), Email: "test@example.com"}
		ctx := auth.WithClaims(context.Background(), claims)
		got, err := requireAuth(ctx)
		if err != nil {
			t.Fatalf("unexpected error: %v", err)
		}
		if got.UserID != claims.UserID {
			t.Errorf("expected UserID %v, got %v", claims.UserID, got.UserID)
		}
	})
}

func TestToGraphQLItem(t *testing.T) {
	title := "Test Title"
	contentText := "Some content"
	contentURL := "https://example.com"
	sourceURL := "https://referrer.com"
	now := time.Now().UTC().Truncate(time.Millisecond)

	it := &item.Item{
		ID:           uuid.New(),
		OwnerID:      uuid.New(),
		Type:         "bookmark",
		Status:       "ready",
		Sensitivity:  "normal",
		Title:        &title,
		ContentText:  &contentText,
		ContentURL:   &contentURL,
		Tags:         []string{"go", "test"},
		Metadata:     map[string]any{"key": "val"},
		AutoMetadata: map[string]any{"auto": true},
		Source:       "chrome_extension",
		SourceURL:    &sourceURL,
		CreatedAt:    now,
		UpdatedAt:    now,
		CapturedAt:   now,
	}

	result := toGraphQLItem(it)

	if result.ID != it.ID.String() {
		t.Errorf("ID mismatch: %s vs %s", result.ID, it.ID.String())
	}
	if result.Type != model.ItemTypeBookmark {
		t.Errorf("Type = %v, want BOOKMARK", result.Type)
	}
	if result.Status != model.ItemStatusReady {
		t.Errorf("Status = %v, want READY", result.Status)
	}
	if result.Sensitivity != model.SensitivityLevelNormal {
		t.Errorf("Sensitivity = %v, want NORMAL", result.Sensitivity)
	}
	if *result.Title != title {
		t.Errorf("Title = %v, want %v", *result.Title, title)
	}
	if *result.ContentText != contentText {
		t.Errorf("ContentText mismatch")
	}
	if *result.ContentURL != contentURL {
		t.Errorf("ContentURL mismatch")
	}
	if len(result.Tags) != 2 {
		t.Errorf("Tags length = %d, want 2", len(result.Tags))
	}
	if result.Source != "chrome_extension" {
		t.Errorf("Source = %q, want 'chrome_extension'", result.Source)
	}
	if *result.SourceURL != sourceURL {
		t.Errorf("SourceURL mismatch")
	}
	if !result.CreatedAt.Equal(now) {
		t.Errorf("CreatedAt mismatch")
	}
}

func TestToGraphQLItemNilFields(t *testing.T) {
	it := &item.Item{
		ID:          uuid.New(),
		OwnerID:     uuid.New(),
		Type:        "text_note",
		Status:      "pending",
		Sensitivity: "public",
		Source:      "api",
		CreatedAt:   time.Now(),
		UpdatedAt:   time.Now(),
		CapturedAt:  time.Now(),
	}

	result := toGraphQLItem(it)

	if result.Title != nil {
		t.Error("expected nil Title")
	}
	if result.ContentText != nil {
		t.Error("expected nil ContentText")
	}
	if len(result.Tags) != 0 {
		t.Errorf("expected empty tags, got %v", result.Tags)
	}
	if result.Metadata == nil {
		t.Error("expected non-nil Metadata map")
	}
	if result.AutoMetadata == nil {
		t.Error("expected non-nil AutoMetadata map")
	}
}

func TestToGraphQLItems(t *testing.T) {
	items := []*item.Item{
		{ID: uuid.New(), Type: "bookmark", Status: "ready", Sensitivity: "normal", Source: "api", CreatedAt: time.Now(), UpdatedAt: time.Now(), CapturedAt: time.Now()},
		{ID: uuid.New(), Type: "text_note", Status: "pending", Sensitivity: "public", Source: "api", CreatedAt: time.Now(), UpdatedAt: time.Now(), CapturedAt: time.Now()},
	}
	result := toGraphQLItems(items)
	if len(result) != 2 {
		t.Fatalf("expected 2 items, got %d", len(result))
	}
	if result[0].Type != model.ItemTypeBookmark {
		t.Errorf("first item type = %v, want BOOKMARK", result[0].Type)
	}
	if result[1].Type != model.ItemTypeTextNote {
		t.Errorf("second item type = %v, want TEXT_NOTE", result[1].Type)
	}
}

func TestToItemFilter(t *testing.T) {
	t.Run("nil returns nil", func(t *testing.T) {
		if got := toItemFilter(nil); got != nil {
			t.Error("expected nil")
		}
	})

	t.Run("converts types to lowercase", func(t *testing.T) {
		f := toItemFilter(&model.ItemFilter{
			Types: []model.ItemType{model.ItemTypeBookmark, model.ItemTypeVoiceNote},
		})
		if len(f.Types) != 2 {
			t.Fatalf("expected 2 types, got %d", len(f.Types))
		}
		if f.Types[0] != "bookmark" {
			t.Errorf("expected 'bookmark', got %q", f.Types[0])
		}
		if f.Types[1] != "voice_note" {
			t.Errorf("expected 'voice_note', got %q", f.Types[1])
		}
	})

	t.Run("passes through source", func(t *testing.T) {
		src := "chrome_extension"
		f := toItemFilter(&model.ItemFilter{Source: &src})
		if f.Source == nil || *f.Source != "chrome_extension" {
			t.Errorf("expected source 'chrome_extension', got %v", f.Source)
		}
	})
}

func TestToItemSort(t *testing.T) {
	t.Run("nil returns nil", func(t *testing.T) {
		if got := toItemSort(nil); got != nil {
			t.Error("expected nil")
		}
	})

	t.Run("converts sort", func(t *testing.T) {
		s := toItemSort(&model.ItemSort{
			Field:     model.ItemSortFieldCreatedAt,
			Direction: model.SortDirectionDesc,
		})
		if s.Field != "CREATED_AT" {
			t.Errorf("expected 'CREATED_AT', got %q", s.Field)
		}
		if s.Direction != "DESC" {
			t.Errorf("expected 'DESC', got %q", s.Direction)
		}
	})
}

func TestSensitivityToString(t *testing.T) {
	t.Run("nil returns normal", func(t *testing.T) {
		if got := sensitivityToString(nil); got != "normal" {
			t.Errorf("expected 'normal', got %q", got)
		}
	})

	t.Run("converts to lowercase", func(t *testing.T) {
		s := model.SensitivityLevelPrivate
		if got := sensitivityToString(&s); got != "private" {
			t.Errorf("expected 'private', got %q", got)
		}
	})
}

func TestEnsureStringSlice(t *testing.T) {
	if got := ensureStringSlice(nil); got == nil {
		t.Error("expected non-nil slice")
	}
	if got := ensureStringSlice([]string{"a"}); len(got) != 1 {
		t.Errorf("expected 1 element, got %d", len(got))
	}
}

func TestEnsureMap(t *testing.T) {
	if got := ensureMap(nil); got == nil {
		t.Error("expected non-nil map")
	}
	if got := ensureMap(map[string]any{"k": "v"}); len(got) != 1 {
		t.Errorf("expected 1 element, got %d", len(got))
	}
}

func TestDerefIntOr(t *testing.T) {
	if got := derefIntOr(nil, 20); got != 20 {
		t.Errorf("expected 20, got %d", got)
	}
	v := 42
	if got := derefIntOr(&v, 20); got != 42 {
		t.Errorf("expected 42, got %d", got)
	}
}

func TestDerefFloat64Or(t *testing.T) {
	if got := derefFloat64Or(nil, 0.5); got != 0.5 {
		t.Errorf("expected 0.5, got %f", got)
	}
	v := 0.8
	if got := derefFloat64Or(&v, 0.5); got != 0.8 {
		t.Errorf("expected 0.8, got %f", got)
	}
}

