func TestToUpperStrings(t *testing.T) {
	tests := []struct {
		input []string
		want  []string
	}{
		{[]string{"bookmark", "text_note"}, []string{"BOOKMARK", "TEXT_NOTE"}},
		{[]string{}, []string{}},
		{[]string{"ALREADY_UPPER"}, []string{"ALREADY_UPPER"}},
	}
	for _, tt := range tests {
		got := toUpperStrings(tt.input)
		if len(got) != len(tt.want) {
			t.Errorf("toUpperStrings(%v) length = %d, want %d", tt.input, len(got), len(tt.want))
			continue
		}
		for i := range got {
			if got[i] != tt.want[i] {
				t.Errorf("toUpperStrings(%v)[%d] = %q, want %q", tt.input, i, got[i], tt.want[i])
			}
		}
	}
}

