interface BookmarkInput {
  url: string;
  title: string | null;
  selection: string | null;
  tags: string[] | null;
  sensitivity: string;
}

interface CaptureMessage {
  action: "captureBookmark";
  input: BookmarkInput;
}

interface CaptureResult {
  success: boolean;
  error?: string;
  data?: {
    id: string;
    status: string;
    title: string;
    tags: string[];
  };
}

interface GraphQLResponse {
  data?: {
    captureBookmark: {
      id: string;
      status: string;
      title: string;
      tags: string[];
    };
  };
  errors?: Array<{ message: string }>;
}

const CAPTURE_MUTATION = `
  mutation CaptureBookmark($input: BookmarkInput!) {
    captureBookmark(input: $input) {
      id
      status
      title
      tags
    }
  }
`;

chrome.runtime.onMessage.addListener(
  (
    message: CaptureMessage,
    _sender: chrome.runtime.MessageSender,
    sendResponse: (response: CaptureResult) => void,
  ) => {
    if (message.action === "captureBookmark") {
      handleCapture(message.input).then(sendResponse);
      return true; // keep message channel open for async response
    }
  },
);

async function handleCapture(input: BookmarkInput): Promise<CaptureResult> {
  try {
    const { apiUrl, jwtToken } = await chrome.storage.local.get([
      "apiUrl",
      "jwtToken",
    ]);

    if (!apiUrl || !jwtToken) {
      return { success: false, error: "Extension not configured" };
    }

    const graphqlUrl = (apiUrl as string).replace(/\/+$/, "") + "/graphql";

    const res = await fetch(graphqlUrl, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: "Bearer " + jwtToken,
      },
      body: JSON.stringify({
        query: CAPTURE_MUTATION,
        variables: { input },
      }),
    });

    if (!res.ok) {
      const text = await res.text();
      return { success: false, error: `HTTP ${res.status}: ${text}` };
    }

    const json: GraphQLResponse = await res.json();

    if (json.errors && json.errors.length > 0) {
      return { success: false, error: json.errors[0].message };
    }

    return { success: true, data: json.data!.captureBookmark };
  } catch (err) {
    return { success: false, error: (err as Error).message };
  }
}

