    @SerializedName("content_type") val contentType: String,
    val size: Long,
)

class ApiClient {

    private val client = OkHttpClient.Builder()
        .connectTimeout(30, TimeUnit.SECONDS)
        .writeTimeout(120, TimeUnit.SECONDS)
        .readTimeout(30, TimeUnit.SECONDS)
        .build()

    private val gson = Gson()

    fun uploadAudio(file: File, baseUrl: String, token: String): UploadResponse {
        val body = MultipartBody.Builder()
            .setType(MultipartBody.FORM)
            .addFormDataPart(
                "file",
                file.name,
                file.asRequestBody("audio/mp4".toMediaType()),
            )
            .build()

        val request = Request.Builder()
            .url("${baseUrl.trimEnd('/')}/upload")
            .header("Authorization", "Bearer $token")
            .post(body)
            .build()

        val response = client.newCall(request).execute()
        if (!response.isSuccessful) {
            val errorBody = response.body?.string() ?: "Unknown error"
            throw IOException("Upload failed (${response.code}): $errorBody")
        }

        val responseBody = response.body?.string()
            ?: throw IOException("Empty response body")

        return gson.fromJson(responseBody, UploadResponse::class.java)
    }

    fun testConnection(baseUrl: String): Boolean {
        val request = Request.Builder()
            .url("${baseUrl.trimEnd('/')}/health")
            .get()
            .build()

        return try {
            val response = client.newCall(request).execute()
            response.isSuccessful
        } catch (_: IOException) {
            false
        }
    }
}

