package com.flotsam.capture.data

import android.content.Context
import androidx.datastore.core.DataStore
import androidx.datastore.preferences.core.Preferences
import androidx.datastore.preferences.core.edit
import androidx.datastore.preferences.core.stringPreferencesKey
import androidx.datastore.preferences.preferencesDataStore
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.map

private val Context.dataStore: DataStore<Preferences> by preferencesDataStore(name = "settings")

class SettingsStore(private val context: Context) {

    private companion object {
        val API_URL = stringPreferencesKey("api_url")
        val JWT_TOKEN = stringPreferencesKey("jwt_token")
    }

    val apiUrl: Flow<String> = context.dataStore.data.map { prefs ->
        prefs[API_URL] ?: ""
    }

    val jwtToken: Flow<String> = context.dataStore.data.map { prefs ->
        prefs[JWT_TOKEN] ?: ""
    }

    suspend fun setApiUrl(url: String) {
        context.dataStore.edit { prefs -> prefs[API_URL] = url }
    }

    suspend fun setJwtToken(token: String) {
        context.dataStore.edit { prefs -> prefs[JWT_TOKEN] = token }
    }
}

